#[cfg(not(verus_keep_ghost))]
fn get_edge_weight<V: StT + Hash + Ord>(
    graph: &LabUnDirGraphStEph<V, WrappedF64>,
    u: &V,
    v: &V,
) -> Option<WrappedF64> {
    for edge in graph.labeled_edges().iter() {
        let LabEdge(a, b, w) = edge;
        if (a == u && b == v) || (a == v && b == u) {
            return Some(*w);
        }
    }
    None
}
